    private static Geometry? _claude, _codex, _copilot;

    public static Geometry? For(ProviderId id)
    {
        try
        {
            if (id == ProviderId.Claude) return _claude ??= Geometry.Parse(ClaudePath);
            if (id == ProviderId.Codex) return _codex ??= Geometry.Parse("F0 " + CodexPath);
            if (id == ProviderId.Copilot) return _copilot ??= Geometry.Parse(CopilotPath);
        }
        catch
        {
            // A geometry that can't be parsed just shows no icon, never crashes the card.
        }
        return null;
    }
